import{_ as d,o as r,c as s,ag as a}from"./chunks/framework.DXGyWiRo.js";const h=JSON.parse('{"title":"消息事件说明","description":"","frontmatter":{"title":"消息事件说明"},"headers":[],"relativePath":"sdk-dev/basics/events.md","filePath":"sdk-dev/basics/events.md","lastUpdated":null}'),e={name:"sdk-dev/basics/events.md"};function n(o,t,g,E,_,T){return r(),s("div",null,[...t[0]||(t[0]=[a('<p>消息事件概述</p><p>本章节详细介绍请求事件和回调事件对应的内部消息类型。AIUI SDK做请求发送和结果接受时，分别通过下面两个事件来进行详细区分:</p><p>**请求事件：**通过构建不同的AIUIMessage进行发送，来实现不同的消息指令请求。</p><p>**回调事件：**通过解析回调中AIUIEvent不同类型，可以获取AIUI SDK抛出的状态或结果。</p><h2 id="aiuimessage" tabindex="-1">AIUIMessage <a class="header-anchor" href="#aiuimessage" aria-label="Permalink to &quot;AIUIMessage&quot;">​</a></h2><p>通过AIUIMessage向SDK发送指令，通过AIUIEvent获取sdk事件回调。</p><p>温馨提示</p><p>有返回值的消息类型，代表向AIUI发送该消息后，AIUI会抛出EVENT_CMD_RETURN事件返回结果。</p><table tabindex="0"><thead><tr><th></th><th></th><th></th><th></th></tr></thead><tbody><tr><td>msgType（消息类型）</td><td>取值</td><td>返回值</td><td>说明</td></tr><tr><td>CMD_GET_STATE</td><td>1</td><td>有</td><td><strong>获取<a href="/sdk-dev/basics/states.html">交互状态</a></strong></td></tr><tr><td>CMD_WRITE</td><td>2</td><td>无</td><td><strong>向AIUI写入数据，回调vad bos事件</strong> 使用参考<a href="/sdk-dev/basics/data-sending.html">数据写入</a>。</td></tr><tr><td>CMD_STOP_WRITE</td><td>3</td><td>无</td><td><strong>停止写入数据，回调vad eos事件</strong> 使用参考<a href="/sdk-dev/basics/data-sending.html">数据写入</a>。</td></tr><tr><td>CMD_START</td><td>5</td><td>无</td><td><strong>启动AIUI</strong> AIUI停止后，使用此命令启动</td></tr><tr><td>CMD_STOP</td><td>6</td><td>无</td><td><strong>停止AIUI</strong> AIUI停止之后，将不响应外部输入。</td></tr><tr><td>CMD_WAKEUP</td><td>7</td><td>无</td><td><strong>唤醒消息</strong> 手动唤醒AIUI，arg1为唤醒后拾音的波束号，默认为0。为了保障识别效果稳定性，请勿将手动唤醒用于延长交互时间。</td></tr><tr><td>CMD_RESET_WAKEUP</td><td>8</td><td>无</td><td><strong>休眠消息</strong> 进入待唤醒状态</td></tr><tr><td>CMD_SET_PARAMS</td><td>10</td><td>无</td><td><strong>动态参数设置</strong> 用params携带参数设置JSON字符串，具体格式参照aiui.cfg文件。 可动态更新参数如下 - global - speech - userparams - audioparams - TTS（语音合成） 示例: <code>{ &quot;global&quot;:{ &quot;scene&quot;:&quot;main&quot; } }</code> 使用参考<a href="/sdk-dev/basics/params.html">基础配置说明</a>。</td></tr><tr><td>CMD_SYNC</td><td>13</td><td>有</td><td><strong>上传个性化数据</strong> arg1表示上传的数据类型 data表示上传的数据内容 使用参考<a href="/sdk-dev/features/personalization.html">用户个性化使用文档</a>。</td></tr><tr><td>CMD_RESULT_VALIDATION_ACK</td><td>20</td><td>无</td><td><strong>结果确认</strong> 收到云端结果5s内发送该指令，重置交互超时的计时。 关于交互超时的机制参看<a href="/sdk-dev/basics/params.html">AIUI配置</a>中interact_timeout的解释。 使用参考<a href="/sdk-dev/basics/data-sending.html">延迟休眠</a>。</td></tr><tr><td>CMD_CLEAN_DIALOG_HISTORY</td><td>21</td><td>无</td><td><strong>清空交互历史</strong> 使用参考<a href="/sdk-dev/basics/data-sending.html">清除历史</a>。</td></tr><tr><td>CMD_START_RECORD</td><td>22</td><td>无</td><td><strong>开始录制数据（暂只支持Android系统）</strong></td></tr><tr><td>CMD_STOP_RECORD</td><td>23</td><td>无</td><td><strong>停止录制数据（暂只支持Android系统）</strong></td></tr><tr><td>CMD_QUERY_SYNC_STATUS</td><td>24</td><td>有</td><td><strong>查询数据同步状态</strong> arg1表示状态查询的类型 params包含查询条件 使用参考<a href="/sdk-dev/features/personalization.html">查询打包状态</a>。</td></tr><tr><td>CMD_TTS</td><td>27</td><td>有</td><td><strong>进行语音合成</strong> arg1表示控制语音合成命令 params包含合成参数 使用参考<a href="/sdk-dev/features/tts.html">云端TTS</a>。</td></tr></tbody></table><h2 id="aiuievent" tabindex="-1">AIUIEvent <a class="header-anchor" href="#aiuievent" aria-label="Permalink to &quot;AIUIEvent&quot;">​</a></h2><p>通过AIUIEvent解析，获取AIUI SDK交互或其他状态信息回调结果。</p><table tabindex="0"><thead><tr><th></th><th></th><th></th></tr></thead><tbody><tr><td>eventType(事件类型)</td><td>取值</td><td>说明</td></tr><tr><td>EVENT_RESULT</td><td>1</td><td><strong>结果事件</strong> 解析参考<a href="/sdk-dev/basics/callbacks.html">结果解析</a>。</td></tr><tr><td>EVENT_ERROR</td><td>2</td><td><strong>出错事件</strong> arg1是错误码，info上错误描述信息。 错误码附录<a href="/sdk-dev/error-codes.html">错误码</a>说明。</td></tr><tr><td>EVENT_STATE</td><td>3</td><td><strong>服务状态事件</strong> 详细见<a href="/sdk-dev/basics/states.html">SDK状态说明</a>。</td></tr><tr><td>EVENT_WAKEUP</td><td>4</td><td><strong>唤醒事件</strong> arg1字段取值： 0 （语音唤醒） 1 （发送CMD_WAKEUP手动唤醒）。 info字段为唤醒结果JSON字符串。</td></tr><tr><td>EVENT_SLEEP</td><td>5</td><td><strong>休眠事件</strong> arg1字段取值： 0 （交互超时,自动休眠） 1 (发送CMD_RESET_WAKEUP，手动休眠)。</td></tr><tr><td>EVENT_VAD</td><td>6</td><td><strong>VAD事件</strong> arg1取值:0(VAD（端点检测） 开始说话)、1(音量)、2(VAD（端点检测） 结束说话)、3（没说话超时）。 当arg1取值为1时，arg2为音量大小。</td></tr><tr><td>EVENT_CMD_RETURN</td><td>8</td><td><strong>某条CMD命令对应的返回事件</strong> 对于除CMD_GET_STATE外的有返回的命令，都会返回该事件， 用arg1标识对应的CMD命令，arg2为返回值，0表示成功，info字段为描述信息。</td></tr><tr><td>EVENT_PRE_SLEEP</td><td>10</td><td><strong>准备休眠事件</strong> 若10s内不交互，则休眠。</td></tr><tr><td>EVENT_START_RECORD</td><td>11</td><td><strong>通知外部录音开始，用户可以开始说话</strong></td></tr><tr><td>EVENT_STOP_RECORD</td><td>12</td><td><strong>通知外部录音停止</strong></td></tr><tr><td>EVENT_CONNECTED_TO_SERVER</td><td>13</td><td><strong>与服务端建立连接</strong></td></tr><tr><td>EVENT_SERVER_DISCONNECTED</td><td>14</td><td><strong>与服务端断开连接</strong></td></tr><tr><td>EVENT_TTS</td><td>15</td><td><strong>语音合成事件</strong> 合成状态以及合成进度，使用参考<a href="/sdk-dev/features/tts.html">云端TTS</a>。</td></tr></tbody></table>',12)])])}const I=d(e,[["render",n]]);export{h as __pageData,I as default};
